// // This comparator outputs '10' when A is less than B, '01' when B is less than A, and '00' when A equals B.
module top_module(input [2:0] A, input [2:0] B, output reg [1:0] result);always @(*) begin
    if (A > B) begin
        result = 2'b10;
    end else if (B > A) begin
        result = 2'b01;
    end else begin
        result = 2'b00;
    end
end

endmodule
